class Solution:
    def bestHand(self, ranks, suits):
        if all(s == suits[0] for s in suits):
            return 'Flush'
        counts = {}
        for r in ranks:
            counts[r] = counts.get(r, 0) + 1
        m = max(counts.values())
        if m >= 3:
            return 'Three of a Kind'
        if m == 2:
            return 'Pair'
        return 'High Card'

