var bestHand = function(ranks, suits) {
    if (new Set(suits).size === 1) return 'Flush';
    const c = new Map();
    for (const r of ranks) c.set(r, (c.get(r) || 0) + 1);
    const m = Math.max(...c.values());
    if (m >= 3) return 'Three of a Kind';
    if (m === 2) return 'Pair';
    return 'High Card';
};
